 1→import { useEffect, useRef, useState } from 'react';
 2→import { addons } from 'storybook/internal/preview-api';
 3→import type { SDUIScreen } from '../../../src/services/sdui/models';
 4→import { EVENTS } from './constants';
 5→
 6→export function useSDUIJsonEditor(defaultScreen: SDUIScreen): SDUIScreen {
 7→  const [screen, setScreen] = useState<SDUIScreen>(defaultScreen);
 8→  const defaultRef = useRef(defaultScreen);
 9→  const prevDefaultRef = useRef<string>('');
10→  defaultRef.current = defaultScreen;
11→
12→  useEffect(() => {
13→    const serialized = JSON.stringify(defaultScreen);
14→    if (serialized === prevDefaultRef.current) return;
15→    prevDefaultRef.current = serialized;
16→    setScreen(defaultScreen);
17→  }, [defaultScreen]);
18→
19→  useEffect(() => {
20→    const channel = addons.getChannel();
21→
22→    const onUpdate = (json: SDUIScreen) => {
23→      setScreen(json);
24→    };
25→
26→    const emitDefault = () => {
27→      channel.emit(
28→        EVENTS.SET_DEFAULT_JSON,
29→        JSON.stringify(defaultRef.current, null, 2),
30→      );
31→    };
32→
33→    channel.on(EVENTS.UPDATE_JSON, onUpdate);
34→    channel.on(EVENTS.REQUEST_DEFAULT, emitDefault);
35→
36→    emitDefault();
37→
38→    return () => {
39→      channel.off(EVENTS.UPDATE_JSON, onUpdate);
40→      channel.off(EVENTS.REQUEST_DEFAULT, emitDefault);
41→    };
42→  }, []);
43→
44→  useEffect(() => {
45→    try {
46→      const channel = addons.getChannel();
47→      channel.emit(
48→        EVENTS.SET_DEFAULT_JSON,
49→        JSON.stringify(defaultScreen, null, 2),
50→      );
51→    } catch {}
52→  }, [defaultScreen]);
53→
54→  return screen;
55→}
